############################################# ### Generated from PreTeXt source ### ### https://pretextbook.org ### ############################################# ## DBsubject() ## DBchapter() ## DBsection() ## Level() ## KEYWORDS() ## TitleText1() ## EditionText1() ## AuthorText1() ## Section1(not reported) ## Problem1(1.2.9.127) ## Author() ## Institution() ## Language(en-US)
DOCUMENT();
############################################################ # Load Macros ############################################################ loadMacros( "PGstandard.pl", "PGML.pl", "AnswerFormatHelp.pl", "contextCurrency.pl", "randomPerson.pl", "PGcourse.pl", ); COMMENT('Authored in PreTeXt');
############################################################ # Header ############################################################ TEXT(beginproblem());
############################################################ # PG Setup Code ############################################################ $name = randomPerson(); $initial = random(80,120,5); Context("Currency")->flags->set(trimTrailingZeros => 1); $start = Currency($initial); $rate = random(12,18); $speed = Currency($rate); $final = $initial + $rate*random(12,23); $end = Currency($final); $solution = ($final - $initial)/$rate; $n = Real($solution);
############################################################ # Body ############################################################
BEGIN_PGML For [$name]'s 8th birthday party, [$name->possessive] parents rented a venue that charges a flat fee of [`[$start]`] plus [`[$speed]`] per guest. Ultimately it cost [$name]'s parents [`[$end]\text{.}`] How many guests were there?
[_]{$n}{20}
END_PGML
############################################################ # End Problem ############################################################
ENDDOCUMENT();
